VALUES
  ('social-worker-moex-04850', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '如果某機構的督導知悉自己的社會工作者與開案中的服務對象一起相約出國旅行，通知機構主管 是屬於何種義務？', '["初始義務", "條件義務", "為人義務", "天賦義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04851', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「安樂死可以解除個人的痛苦，以及減輕家庭與社會的照顧成本，故應合法化。」此種論點是何 種倫理學的主張？', '["效益主義", "社群主義", "義務論", "自決論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04852', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一名因意外而導致下半身癱瘓的身心障礙服務對象獨居多年。近日，該服務對象又因故跌倒在 地、骨折受傷無力爬起。直到隔日，居家服務員到訪，才被發現送醫。社會工作者為避免服務對 象再度有安全風險，故積極促成服務對象入住長期安養單位。為了讓服務對象能夠順利獲得安 置，社會工作者在轉介過程中，並未告知服務對象安置機構情況，也向機構隱瞞服務對象在前次 安養機構的自殺史。該名社會工作者可能違反什麼社會工作倫理守則？', '["保障隱私的義務", "不與案主利益衝突的義務", "提供明確評估指標的義務", "適當轉介的義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04853', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '精神醫療社會工作可簡單區分為「以院舍和病症為本」和「以社區和病人為本」兩種工作取向，', '["以社區和病人為本的工作理念強調以融入社區、精神康復及正常生活為主", "以社區和病人為本的工作取向注重病人的全人和潛能發展", "以院舍和病症為本的工作理念 是以診斷治療為主", "以院舍和病症為本的工作取向著重於多元手法和社區的改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04854', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '臺灣的老年女性獨居人數增加趨勢中，看到女性老年未婚人口有增多現象。若從個人層面來看未 婚高齡女性的準備進入老年階段的方案，下列那一項不屬於個人層面之需求？', '["加長社區主要道路交通號誌秒數", "退休角色適應與時間安排", "生病的照顧問題", "後事安排"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04855', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '初級預防的兒童福利服務工作是以預防家庭解組和兒童虐待為目標，下列何者不屬於初級預防策略？', '["法院強制進行親職輔導", "到宅訪視以提供支持性服務", "協助新手父母建立社會網絡和教導父母關於兒童發展知能", "提供兒童托育的機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04856', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '弱勢與高關懷青少年復原力（resilience）保護因子受到重視。下列何者不是青少年復原力保護因子？', '["家庭成員對青少年的關懷和親密感", "社區有多元參與管道和機會", "主要照顧者降低對青少年成就期待", "學校提供青少年關懷與支持"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04857', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於身心障礙者去機構化與正常化之敘述，何者正確？①去機構化就等同於讓身心障礙者正常化', '["北美正常化觀點試圖強調結構面改革與障礙者平等公民權保障；北歐正常化觀點則著重 於推動專業服務模式的改變", "去機構化與正常化的論述是專業人員的反省", "Wolfensberger 於1980年發展社會角色隱持觀點（Social Role Valorization），主張心智障礙者往往被多數群體 貶抑，且越無法扮演社會角色就越被社會所貶抑", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04858', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依據學生輔導法的制度設計，我國學校社會工作師主要負責那一種層次的學生輔導工作？', '["發展性輔導", "處遇性輔導", "介入性輔導", "預防性輔導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04859', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關臺灣精神醫療社會工作發展脈絡之敘述，何者正確？', '["1986-1994年，精神醫療體系以精神分析學派為主流，重視病人生理、心理與社會層面的治療", "臺灣精神醫療社會工作與精神科醫院評鑑開始於1947年", "1995年迄今，醫療院所雖受到全民健康保險實施的影響，但在醫療服務上仍以病人的需求為 主要考量，績效指標次之", "1986-1994年家族治療在精神科萌芽，同時社區心理衛生工作蓬勃發展，社會工作者不僅在團 隊中擔任重要的治療者角色，也是推展社區工作的主力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
